final:
module RefModule(    
    input clk,
    input rst,
    input data_in,
    output reg data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        data_out <= 0;
    else
        data_out <= data_in;
end

endmodule
